    [Serializable]
    public class Permission
    {
        public string Name { get; set; }
        public string Resource { get; set; }
        public PermissionLevel Level { get; set; }
        public DateTime GrantedAt { get; set; }
        public DateTime? ExpiresAt { get; set; }

        public Permission(string name, string resource, PermissionLevel level)
        {
            Name = name;
            Resource = resource;
            Level = level;
            GrantedAt = DateTime.UtcNow;
        }

        public bool IsExpired()
        {
            return ExpiresAt.HasValue && DateTime.UtcNow > ExpiresAt.Value;
        }

        public bool HasAccess(PermissionLevel requiredLevel)
        {
            if (IsExpired()) return false;
            return Level >= requiredLevel;
        }

        public Permission Elevate(PermissionLevel newLevel)
        {
            if (newLevel <= Level)
                throw new InvalidOperationException("Cannot elevate to a lower or equal permission level.");
            Level = newLevel;
            return this;
        }

        public Permission WithExpiry(TimeSpan duration)
        {
            ExpiresAt = DateTime.UtcNow + duration;
            return this;
        }

        public override string ToString()
        {
            string expiry = ExpiresAt.HasValue ? $", Expires: {ExpiresAt.Value}" : ", No expiry";
            return $"Permission[{Name}] Resource: {Resource}, Level: {Level}{expiry}";
        }
    }

    [Serializable]
    public enum PermissionLevel
    {
        None = 0,
        Read = 1,
        Write = 2,
        Execute = 3,
        Admin = 4
    }

