        }

        public bool HasPermission(string resource, PermissionLevel requiredLevel)
        {
            foreach (var perm in Permissions)
            {
                if (perm.Resource == resource && perm.HasAccess(requiredLevel))
                    return true;
            }
            return false;
        }

        public List<Permission> GetActivePermissions()
        {
            return Permissions.FindAll(p => !p.IsExpired());
