                return session;
            }
        }

        public UserSession GetSession(string sessionId)
        {
            lock (_lock)
            {
                if (_activeSessions.TryGetValue(sessionId, out var session))
                {
                    if (session.IsExpired())
                    {
                        Console.WriteLine($"[SessionManager] Session {sessionId} has expired (in-memory).");
                        DestroySession(sessionId);
                        return null;
                    }
                    session.Touch();
                    return session;
                }

                session = LoadSessionFromDisk(sessionId);
                if (session != null)
                {
                    if (session.IsExpired())
                    {
                        Console.WriteLine($"[SessionManager] Session {sessionId} has expired (on-disk).");
                        DestroySession(sessionId);
                        return null;
