                    session.Touch();
                    _activeSessions[sessionId] = session;
                }
                return session;
            }
        }

        public void SaveSession(UserSession session)
        {
            lock (_lock)
            {
                _activeSessions[session.SessionId] = session;
                SaveSessionToDisk(session);
            }
        }

        public bool DestroySession(string sessionId)
