                    return true;
                }
                return false;
            }
        }

        public int CleanExpiredSessions()
        {
            lock (_lock)
            {
                int cleaned = 0;
                var expiredKeys = new List<string>();

                foreach (var kvp in _activeSessions)
                {
                    if (kvp.Value.IsExpired())
                        expiredKeys.Add(kvp.Key);
                }

                foreach (var key in expiredKeys)
                {
                    DestroySession(key);
                    cleaned++;
                }

                foreach (var file in Directory.GetFiles(_sessionDirectory, "*.session"))
                {
                    var session = LoadSessionFromDiskByPath(file);
                    if (session != null && session.IsExpired())
                    {
                        File.Delete(file);
                        _activeSessions.Remove(session.SessionId);
                        cleaned++;
                    }
                }

                Console.WriteLine($"[SessionManager] Cleaned {cleaned} expired sessions.");
                return cleaned;
            }
        }

        public List<UserSession> GetAllActiveSessions()
        {
