            {
                var sessions = new List<UserSession>();
                foreach (var file in Directory.GetFiles(_sessionDirectory, "*.session"))
                {
                    var session = LoadSessionFromDiskByPath(file);
                    if (session != null && !session.IsExpired())
                    {
                        sessions.Add(session);
                    }
                }
                return sessions;
            }
        }

        public List<UserSession> GetSessionsByUserId(string userId)
        {
            var all = GetAllActiveSessions();
            return all.FindAll(s => s.UserId == userId);
